import 'server-only';

import { unstable_cache } from 'next/cache';

export type Post = {
  id: string;
  title: string;
  body: string;
  createdAt: string;
};

const posts: Post[] = [];

export const getPosts = unstable_cache(
  async () => posts.map((post) => ({ ...post })),
  ['posts'],
  { tags: ['posts'] }
);

export function addPost(title: string, body: string): Post {
  const post: Post = {
    id: crypto.randomUUID(),
    title,
    body,
    createdAt: new Date().toISOString()
  };

  posts.unshift(post);
  return post;
}

